const stageForEffects=document.getElementById('stage');
const miniDotGrid=`<svg viewBox='0 0 120 120'><rect width='120' height='120' fill='none'/>${Array.from({length:4},(_,y)=>Array.from({length:4},(_,x)=>`<circle cx='${20+x*24}' cy='${20+y*24}' r='5' fill='#76ff72' opacity='${0.45+((x+y)%3)*0.12}'/>`).join('')).join('')}</svg>`;
const miniX=`<svg viewBox='0 0 120 120'><g stroke='#76ff72' stroke-width='12' stroke-linecap='round' opacity='.88'><path d='M26 26L94 94'/><path d='M94 26L26 94'/></g><g stroke='#76ff72' stroke-width='3' stroke-linecap='round' opacity='.4'><path d='M22 18L98 94'/><path d='M98 18L22 94'/></g></svg>`;
const miniBars=`<svg viewBox='0 0 150 150'><g fill='#76ff72' opacity='.82'><rect x='22' y='18' width='92' height='12'/><rect x='32' y='40' width='80' height='10'/><rect x='28' y='60' width='88' height='10'/><rect x='24' y='80' width='84' height='10'/><rect x='20' y='100' width='92' height='11'/></g></svg>`;
const miniStickerSkull=`<svg viewBox='0 0 120 150'><rect width='120' height='150' fill='none'/><path d='M60 20c-25 0-40 16-40 39 0 17 8 28 18 34v22h44V93c10-6 18-17 18-34 0-23-15-39-40-39z' fill='#76ff72'/><g fill='#020402'><circle cx='44' cy='58' r='12'/><circle cx='76' cy='58' r='12'/><path d='M60 68l-8 18h16z'/></g><g fill='#76ff72' opacity='.72'><circle cx='44' cy='120' r='4'/><circle cx='58' cy='121' r='4'/><circle cx='72' cy='120' r='4'/></g></svg>`;
function makePopLayer(){const layer=document.createElement('div');layer.className='pop-layer';stageForEffects.appendChild(layer);return layer}
const popLayer=makePopLayer();
const popTemplates=[{cls:'pop-grid',html:miniDotGrid,min:34,max:82},{cls:'pop-x',html:miniX,min:40,max:92},{cls:'pop-bars',html:miniBars,min:48,max:98},{cls:'pop-skull',html:miniStickerSkull,min:44,max:88}];
function rand(min,max){return Math.random()*(max-min)+min}
function addInfectedSticker(){if(document.hidden||!stageForEffects)return;const pick=popTemplates[Math.floor(Math.random()*popTemplates.length)];const node=document.createElement('div');node.className=`pop-item ${pick.cls}`;const size=rand(pick.min,pick.max);node.style.width=`${size}px`;node.style.left=`${rand(1,84)}%`;node.style.top=`${rand(3,83)}%`;node.style.setProperty('--rot',`${rand(-18,18)}deg`);node.style.animationDuration=`${rand(3.8,7.2)}s`;node.style.animationDelay=`${rand(0,0.18)}s`;node.style.opacity=String(rand(.4,.9));node.innerHTML=pick.html;popLayer.appendChild(node);while(popLayer.children.length>15){popLayer.removeChild(popLayer.firstChild)}setTimeout(()=>node.remove(),7600)}
for(let i=0;i<6;i++)setTimeout(addInfectedSticker,300+i*210);
setInterval(addInfectedSticker,880);
